public int numberOfEvenSubarrays(int[] nums) {
    int n = nums.length;
    int evenCount = 0, oddCount = 0, result = 0;

    for (int num : nums) {
        if (num % 2 == 0) {
            evenCount++;
            result += evenCount;
        } else {
            int temp = evenCount;
            evenCount = oddCount;
            oddCount = temp;
            oddCount++;
            result += oddCount;
        }
    }

    return result;
}
```

